function tagsFromTrackPath(trackRelPath) {
  const base = String(trackRelPath || '').split('/').pop().replace(/\.[^.]+$/, '');
  const chunks = base.split(/[-–—_\s]+/).map((s) => s.replace(/^\d+\s*/, '').trim().toLowerCase()).filter((s) => s.length > 2);
  const out = [];
  for (const c of chunks.slice(0, 5)) {
    const t = c.replace(/[^a-z0-9\u0400-\u04FF-]/gi, '');
    if (t.length > 1) out.push(t);
  }
  return out;
}

function mergeTags(presetTags, extra, maxLen) {
  const seen = new Set();
  const res = [];
  for (const t of [...presetTags, ...extra]) {
    const k = String(t).toLowerCase();
    if (!k || seen.has(k)) continue;
    seen.add(k);
    res.push(t);
    if (res.length >= maxLen) break;
  }
  return res;
}

const sd = $getWorkflowStaticData('global');
const entry = sd.entrySource || 'cron';
const tracks = $input.first().json.tracks || [];

if (!tracks.length) {
  return [];
}

sd.pendingShorts = sd.pendingShorts || [];
sd.nextLongTrackIndex = sd.nextLongTrackIndex ?? 0;
sd.mainMeta = sd.mainMeta || { title: '', description: '', tags: [] };

if (entry === 'manual') {
  if (sd.pendingShorts.length > 0) return [];
  if (sd.nextLongTrackIndex !== 0) return [];
}

if (sd.pendingShorts.length > 0) {
  const head = sd.pendingShorts[0];
  const meta = sd.mainMeta;
  return [{
    json: {
      kind: 'publish',
      publishBody: {
        short_path: head.path,
        main_title: meta.title || 'Short',
        description: meta.description || '',
        tags: Array.isArray(meta.tags) ? meta.tags : [],
        short_index: typeof head.index === 'number' ? head.index : 0,
        shorts_privacy_status: 'public',
        cleanup_after: true
      }
    }
  }];
}

if (sd.nextLongTrackIndex >= tracks.length) {
  return [];
}

if (entry === 'cron' && sd.nextLongTrackIndex === 0) {
  return [];
}

const idx = sd.nextLongTrackIndex;
const track = tracks[idx];
const preset = ROLL_PRESETS[idx % ROLL_PRESETS.length];
const theme = preset.theme;
const tags = mergeTags(preset.tags, tagsFromTrackPath(track), 15);

return [{
  json: {
    kind: 'render',
    renderBody: {
      track,
      allow_recent_preferred: false,
      tags,
      theme,
      publish_at_iso: new Date().toISOString(),
      shorts_count: 3,
      short_publish_offset_hours: [12, 24, 36],
      shorts_use_main_track_thirds: true,
      main_privacy_status: 'public',
      shorts_privacy_status: 'public',
      cleanup_source_after_publish: true,
      cleanup_shorts_after_upload: true,
      clip_seconds: 30
    }
  }
}];

const body = $input.first().json;
const sd = $getWorkflowStaticData('global');
const w = body.workflow || {};
const files = w.shorts_files || [];
sd.pendingShorts = files.map((f) => ({ path: f.path, index: f.index }));
const mm = w.main_meta || {};
sd.mainMeta = {
  title: mm.title || '',
  description: mm.description || '',
  tags: Array.isArray(mm.tags) ? mm.tags : []
};
sd.nextLongTrackIndex = (sd.nextLongTrackIndex ?? 0) + 1;
return [{ json: { committed: 'render', shortsQueued: sd.pendingShorts.length, nextLongTrackIndex: sd.nextLongTrackIndex } }];

const sd = $getWorkflowStaticData('global');
if (sd.pendingShorts && sd.pendingShorts.length) {
  sd.pendingShorts.shift();
}
return [{ json: { committed: 'publish', remainingShorts: sd.pendingShorts.length } }];
